import './index.css';

import {
  useEffect,
  useState
} from 'react';

import Header
from '../../components/common/Header';

import {
  getStudentMarks
} from '../../services/studentMarksService';

function StudentMarks() {

  const [marks, setMarks] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadMarks();

  }, []);

  // LOAD MARKS
  const loadMarks =
    async () => {

    try {

      const data =
        await getStudentMarks();

      console.log(data);

      setMarks(data);

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-marks-page">

      {/* HEADER */}

      <Header />


      {/* CONTENT */}

      <div className="student-marks-content">

        <h1>
          My Marks
        </h1>

        {

          loading
          ? (

            <h2>
              Loading...
            </h2>

          )
          : (

            <div className="marks-grid">

              {

                marks.length > 0
                ? (

                  marks.map((mark) => (

                    <div
                      key={mark.id}
                      className="mark-card"
                    >

                      <h3>
                        {mark.subject_name}
                      </h3>

                      <p>

                        <strong>
                          Subject ID:
                        </strong>

                        {' '}

                        {mark.subject_id}

                      </p>

                      <p>

                        <strong>
                          Assessment ID:
                        </strong>

                        {' '}

                        {mark.assessment_id}

                      </p>

                      <p>

                        <strong>
                          Marks:
                        </strong>

                        {' '}

                        {mark.marks_obtained}

                      </p>

                      <p>

                        <strong>
                          Percentage:
                        </strong>

                        {' '}

                        {mark.percentage}%

                      </p>

                      <p>

                        <strong>
                          Grade:
                        </strong>

                        {' '}

                        {mark.grade}

                      </p>

                    </div>

                  ))

                )
                : (

                  <div className="empty-box">

                    No Marks Available

                  </div>

                )

              }

            </div>

          )

        }

      </div>

    </div>

  );

}

export default StudentMarks;
